head.script:
scwin.onpageload = function() {
    // 부모 화면에서 안전하게 던져준 JSON 데이터 꺼내기
    let receiveData = $p.getParameter("paramData");

    if(receiveData) {
        console.log("부모 창에서 넘어온 데이터: ", receiveData);

        //넘어온 데이터를 화면 컴포넌트에 바인딩
        let infoStr = "나이: " + receiveData.age + "/ 주질병: " + receiveData.diseaseCode;
        tbx_info.setValue(infoStr);
    } else {
        alert("전달된 데이터가 없습니다.");
    }
};

scwin.btn_close_onclick = function(e) {
    // 팝업 닫기
    $p.closePopup();
}
